```class Solution {
public:
    int possibleStringCount(string word, int k) {
        const int MOD = 1e9 + 7;
        int n = word.size();
        vector<int> cnt(26, 0);
        for (char c : word) cnt[c - 'a']++;
        int res = 1;
        for (int i = 0; i < 26; i++) {
            if (cnt[i] >= k) res = res * (cnt[i] - k + 1) % MOD;
        }
        return res;
    }
};
